#include <iostream>
#include <cmath>
#include <iomanip>
using namespace std;
int main()
{
	int n,ans=0;
    cin>>n;
    for(int i=2;i<=n;i++){
        int cnt=0;
        for(int k=1;k<=i;k++){
            if(i%k==0){
                cnt++;
            }
            if(cnt>=3) break;
        }
        if(cnt==2) ans++;
    }
	cout<<ans;
	return 0;
}
